// ─── PUBMED — efetch via proxy (paginated, heartbeat-safe) ───
const input = $input.all()[0].json;
const query = encodeURIComponent(input.pubmed_query || input.search_query || '');
const meta = {
  question: input.question || '',
  criteria: input.criteria || '',
  search_query: input.search_query || '',
  output_folder: input.output_folder || '',
  prefilter_enabled: input.prefilter_enabled,
  prefilter_count: input.prefilter_count,
  max_results: input.max_results,
  pubmed_query: input.pubmed_query || '',
  openalex_query: input.openalex_query || '',
  crossref_query: input.crossref_query || ''
};

const PROXY = 'http://host.docker.internal:3456';
const BATCH = 200;
const MAX_RESULTS = parseInt(input.max_results) || 1000;
let allArticles = [];

try {
  // esearch
  const searchTarget = `https://eutils.ncbi.nlm.nih.gov/entrez/eutils/esearch.fcgi?db=pubmed&term=${query}&retmax=0&usehistory=y&retmode=json`;
  const searchResp = await this.helpers.httpRequest({
    method: 'GET',
    url: PROXY + '?url=' + encodeURIComponent(searchTarget),
    timeout: 60000
  });

  const sr = searchResp.esearchresult || {};
  const totalCount = Math.min(parseInt(sr.count || '0'), MAX_RESULTS);
  const webEnv = sr.webenv || '';
  const queryKey = sr.querykey || '';

  console.log(`PubMed: ${sr.count} results found, fetching up to ${totalCount}`);

  if (totalCount === 0 || !webEnv) {
    return [{ json: { _source: 'pubmed', _empty: true, ...meta } }];
  }

  // efetch in batches
  for (let retStart = 0; retStart < totalCount; retStart += BATCH) {
    const fetchTarget = `https://eutils.ncbi.nlm.nih.gov/entrez/eutils/efetch.fcgi?db=pubmed&WebEnv=${encodeURIComponent(webEnv)}&query_key=${queryKey}&retstart=${retStart}&retmax=${BATCH}&rettype=xml&retmode=xml`;

    let xmlText;
    try {
      const xmlResp = await this.helpers.httpRequest({
        method: 'GET',
        url: PROXY + '?url=' + encodeURIComponent(fetchTarget),
        timeout: 120000
      });
      xmlText = typeof xmlResp === 'string' ? xmlResp : JSON.stringify(xmlResp);
    } catch(e) {
      console.log('PubMed batch error at ' + retStart + ': ' + e.message);
      continue;
    }

    const blocks = xmlText.split('<PubmedArticle>');
    for (let i = 1; i < blocks.length; i++) {
      const b = blocks[i];
      const title = ((b.match(/<ArticleTitle>([\s\S]*?)<\/ArticleTitle>/) || [])[1] || '').replace(/<[^>]+>/g, '').trim();

      let abstract = '';
      const absMatch = b.match(/<Abstract>([\s\S]*?)<\/Abstract>/);
      if (absMatch) {
        const parts = absMatch[1].match(/<AbstractText[^>]*>([\s\S]*?)<\/AbstractText>/g);
        if (parts) abstract = parts.map(t => t.replace(/<[^>]*>/g, '').trim()).join(' ');
      }

      const authors = [];
      const authMatches = b.match(/<Author[^>]*>[\s\S]*?<\/Author>/g);
      if (authMatches) {
        for (const a of authMatches) {
          const last = ((a.match(/<LastName>([^<]+)<\/LastName>/) || [])[1] || '');
          const fore = ((a.match(/<ForeName>([^<]+)<\/ForeName>/) || [])[1] || '');
          if (last) authors.push((fore + ' ' + last).trim());
        }
      }

      const year = ((b.match(/<PubDate>[\s\S]*?<Year>(\d{4})<\/Year>/) || [])[1] || '');
      const journal = ((b.match(/<Title>([^<]+)<\/Title>/) || [])[1] || '').trim();
      const doi = ((b.match(/<ArticleId IdType="doi">([^<]+)<\/ArticleId>/) || [])[1] || '').trim();
      const pmid = ((b.match(/<PMID[^>]*>(\d+)<\/PMID>/) || [])[1] || '');

      if (title) {
        allArticles.push({
          _source: 'pubmed',
          id: pmid ? 'pmid:' + pmid : '',
          doi: doi,
          title: title,
          abstract: abstract,
          authors: authors,
          year: year,
          journal: journal,
          ...meta
        });
      }
    }

    console.log(`PubMed batch ${retStart}: +${blocks.length - 1} (total: ${allArticles.length})`);
    await new Promise(r => setTimeout(r, 400));
  }
} catch(e) {
  console.log('PubMed fatal error: ' + e.message);
}

console.log('PubMed DONE: ' + allArticles.length + ' articles');

if (allArticles.length === 0) {
  return [{ json: { _source: 'pubmed', _empty: true, ...meta } }];
}
return allArticles.map(a => ({ json: a }));

const items = $input.all();
const filtered = items.filter(item => !item.json._empty);

// Count per source for diagnostics
const counts = {};
for (const item of filtered) {
  const src = item.json._source || 'unknown';
  counts[src] = (counts[src] || 0) + 1;
}

console.log('=== SEARCH RESULTS SUMMARY ===');
console.log('OpenAlex: ' + (counts.openalex || 0) + ' articles');
console.log('Crossref: ' + (counts.crossref || 0) + ' articles');
console.log('PubMed: ' + (counts.pubmed || 0) + ' articles');
console.log('TOTAL: ' + filtered.length + ' articles');

if (counts.openalex === 0) console.log('WARNING: OpenAlex returned 0 results!');
if (counts.crossref === 0) console.log('WARNING: Crossref returned 0 results!');
if (counts.pubmed === 0) console.log('WARNING: PubMed returned 0 results!');

if (filtered.length === 0) {
  return [{ json: { error: 'No results from any API', _source: 'none' } }];
}

return filtered;

// === DIRECT_ARTICLES_BYPASS_v1 - skip si articles fournis directement
const __DIRECT = $input.all()[0] && $input.all()[0].json;
if (__DIRECT && Array.isArray(__DIRECT.direct_articles) && __DIRECT.direct_articles.length > 0) {
  return [];
}

// === Semantic Scholar Fetch (v0.2.5+) ===
// https://api.semanticscholar.org/graph/v1/paper/search - 200M papers, gratuit
const PROXY = 'http://host.docker.internal:3456';
const data = __DIRECT || {};
const query = data.semantic_query || data.openalex_query || data.pubmed_query || data.question || '';
const maxResults = parseInt(data.max_results) || 200;
const limit = Math.min(maxResults, 100);

if (!query) {
  console.log('[Semantic Scholar] pas de query, skip');
  return [];
}

const fields = 'title,abstract,authors.name,year,externalIds,journal,publicationTypes,publicationVenue';
const apiUrl = 'https://api.semanticscholar.org/graph/v1/paper/search?query=' +
               encodeURIComponent(query) + '&limit=' + limit + '&fields=' + fields;
const proxyUrl = PROXY + '?url=' + encodeURIComponent(apiUrl);

const articles = [];
try {
  const resp = await this.helpers.httpRequest({
    method: 'GET',
    url: proxyUrl,
    timeout: 30000,
    json: true
  });
  const papers = (resp && resp.data) || [];
  console.log('[Semantic Scholar] ' + papers.length + ' papers recus');
  for (let i = 0; i < papers.length; i++) {
    const p = papers[i];
    const authors = ((p.authors || []).map(function(a){ return a && a.name ? a.name : ''; })).filter(Boolean);
    const ext = p.externalIds || {};
    const venue = (p.journal && p.journal.name) || (p.publicationVenue && p.publicationVenue.name) || '';
    articles.push({
      title: p.title || '',
      abstract: p.abstract || '',
      authors: authors,
      year: p.year ? String(p.year) : '',
      doi: ext.DOI || '',
      pmid: ext.PubMed || '',
      issn: '',
      journal: venue,
      source: 'semanticscholar'
    });
  }
} catch (e) {
  console.log('[Semantic Scholar] erreur fetch : ' + (e && e.message ? e.message : e));
}

return articles.map(function(a) { return { json: a }; });
